arguments.command:
$ErrorActionPreference='Stop'
$base=$env:SUPABASE_URL;$key=$env:SUPABASE_SERVICE_ROLE_KEY;$headers=@{apikey=$key; Authorization="Bearer $key"}
$agents=Invoke-RestMethod -Method Get -Uri "$base/rest/v1/agents?select=agent_id,display_name,org_unit,status,last_heartbeat_at&limit=200" -Headers $headers -UserAgent "openclaw-healthcheck/1.0"
$now=[DateTimeOffset]::UtcNow
$stale=@()
foreach($a in $agents){
  $hb=$null
  if($a.last_heartbeat_at){ $hb=[DateTimeOffset]::Parse($a.last_heartbeat_at) }
  $mins = if($hb){ [math]::Round(($now-$hb).TotalMinutes,1) } else { $null }
  if((-not $hb) -or $mins -gt 30){
    $stale += [pscustomobject]@{agent_id=$a.agent_id;display_name=$a.display_name;org_unit=$a.org_unit;status=$a.status;last_heartbeat_at=$a.last_heartbeat_at;stale_minutes=$mins}
  }
}
$summary=[pscustomobject]@{
  checked_at_utc=$now.ToString('o')
  total_agents=$agents.Count
  stale_over_30m=$stale.Count
  stale_null_heartbeat=($stale | Where-Object { -not $_.last_heartbeat_at }).Count
  stale_with_timestamp=($stale | Where-Object { $_.last_heartbeat_at }).Count
  stale_top=($stale | Sort-Object @{Expression={ if($_.stale_minutes -eq $null){1e9}else{$_.stale_minutes}}} -Descending | Select-Object -First 12)
}
$summary | ConvertTo-Json -Depth 6

