arguments.command:
$ErrorActionPreference='Stop'
$base=$env:SUPABASE_URL;$key=$env:SUPABASE_SERVICE_ROLE_KEY;$headers=@{apikey=$key; Authorization="Bearer $key"; 'Content-Type'='application/json'; Prefer='return=representation'}
$now=[DateTime]::UtcNow.ToString('o')
$payload=@(@{
  event_name='agent/escalate'
  source_agent='shared_master_orchestrator'
  target_agent='d1_cto'
  target_division='division_1_core_operations'
  payload=@{
    severity='critical'
    summary='Hourly agent network health check detected global stale heartbeat + telemetry gap'
    details=@{
      stale_heartbeats_over_30m=67
      total_agents=67
      agent_metrics_rows=0
      checks_blocked=@('error_rate','response_time','memory_utilization')
      observed_at_utc=$now
    }
  }
  priority='critical'
}) | ConvertTo-Json -Depth 8
$resp=Invoke-RestMethod -Method Post -Uri "$base/rest/v1/agent_events" -Headers $headers -UserAgent "openclaw-healthcheck/1.0" -Body $payload
$resp | ConvertTo-Json -Depth 5

